#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, P;
        scanf("%d %d", &N, &P);
        int M;
        scanf("%d", &M);
        int arr[N];
        for (int i = 0; i < N; i++) {
            arr[i] = 0;
        }
        for (int i = 0; i < M; i++) {
            int Fi, Ci, Di, Li;
            scanf("%d %d %d %d", &Fi, &Ci, &Di, &Li);
            for (int j = Fi; j <= Di; j++) {
                arr[j] = (arr[j] + Ci) % P;
            }
        }
        int count = 0;
        for (int i = 0; i < N; i++) {
            if (arr[i] != 0) {
                count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

